describe('Gungeon Code Decoder / 銃の牢獄デコーダー', () => {
  describe('HTML Decoding', () => {
    it('decodes chamber HTML', () => {
      const html = gungeonDecoder.decodeChamberHTML('KEEP');
      expect(html).toContain('<');
      expect(html.length).toBeGreaterThan(0);
    });

