        const html = gungeonDecoder.decodeChamberHTML(chamber);
        expect(html).toBeDefined();
        expect(typeof html).toBe('string');
      });
    });
  });

  describe('Fan Pattern Rotation', () => {
    it('decodes with 180 rotation (fan)', () => {
      const html = gungeonDecoder.decodeWithRotation(180);
      expect(html).toContain('html');
    });

    it('gets fan pattern value', () => {
      const straight = gungeonDecoder.getFanPattern('straight');
      const fan180 = gungeonDecoder.getFanPattern('fan180');
      expect(straight).toBe(0);
      expect(fan180).toBe(180);
    });

    it('cycles with full rotation', () => {
      const html360 = gungeonDecoder.decodeWithRotation(360);
      const html0 = gungeonDecoder.decodeWithRotation(0);
      expect(html360).toContain('<');
      expect(html0).toContain('<');
    });
  });

  describe('Temporal Decoders', () => {
    it('decodes weekly pattern', () => {
      const html = gungeonDecoder.decodeWeekly(3); // Wednesday
      expect(html).toContain('html');
    });

    it('decodes monthly pattern', () => {
      const html = gungeonDecoder.decodeMonthly(15);
      expect(html).toContain('html');
    });

    it('different days produce different results', () => {
      const monday = gungeonDecoder.decodeWeekly(1);
      const friday = gungeonDecoder.decodeWeekly(5);
      // Different rotations should produce different strings
      expect(monday).toBeDefined();
      expect(friday).toBeDefined();
    });
  });

  describe('atob Decoding', () => {
    it('decodes base64', () => {
      const encoded = Buffer.from('Gungeon').toString('base64');
      const decoded = gungeonDecoder.decodeAtob(encoded);
      expect(decoded).toBe('Gungeon');
    });

    it('handles regular strings', () => {
      const decoded = gungeonDecoder.decodeAtob('Gungeon');
      expect(decoded).toBe('Gungeon');
    });
  });

  describe('Eval Pattern', () => {
    it('decodes eval pattern', () => {
      const input = 'R3VuZ2Vvbg=='; // "Gungeon" base64
      const decoded = gungeonDecoder.decodeEvalPattern(input);
      expect(decoded).toBe('Gungeon');
    });
  });

  describe('Hidden Link Extraction', () => {
    it('extracts hidden link from rotated code', () => {
      const link = gungeonDecoder.extractHiddenLink(180);
      expect(typeof link).toBe('string');
    });
  });

  describe('Fan Pattern Values', () => {
    it('has all pattern values', () => {
      expect(gungeonDecoder.getFanPattern('straight')).toBe(0);
      expect(gungeonDecoder.getFanPattern('diagonal')).toBe(45);
      expect(gungeonDecoder.getFanPattern('fan180')).toBe(180);
      expect(gungeonDecoder.getFanPattern('reverse')).toBe(360);
    });
  });

  describe('Indicator Patterns', () => {
    it('decodes 0#0#0#0 pattern', () => {
      // Pattern from input: 0#0#0#0
      const codes = [0x30, 0x23, 0x30, 0x23, 0x30, 0x23, 0x30];
      const decoded = codes.map(c => String.fromCharCode(c)).join('');
      expect(decoded).toContain('0');
      expect(decoded).toContain('#');
    });

    it('handles fan/180 indicator', () => {
      const rotation = gungeonDecoder.getFanPattern('fan180');
      expect(rotation).toBe(180);
    });
  });
});
